from matplotlib import pyplot as pltimport cv2from skimage import ioimport numpy as npimg = io.imread("../data/bio_low_contrast.jpg")if img is None:    raise FileNotFoundError("Image not loaded. Check your file path.")print("Image shape:", img.shape)if len(img.shape) == 2:    # Histogram Equalization    hist_eq_img = cv2.equalizeHist(img)    # CLAHE    clahe = cv2.createCLAHE(        clipLimit=3.0,        tileGridSize=(8, 8)    )    clahe_img = clahe.apply(img)else:    # skimage reads image as RGB, but OpenCV uses BGR    img_bgr = cv2.cvtColor(img, cv2.COLOR_RGB2BGR)    # Convert BGR image to LAB color space    lab_img = cv2.cvtColor(img_bgr, cv2.COLOR_BGR2LAB)    # Split LAB image into L, A, and B channels    l, a, b = cv2.split(lab_img)    # Histogram Equalization on L channel    equ = cv2.equalizeHist(l)    # Merge equalized L channel with original A and B channels    updated_lab_img = cv2.merge((equ, a, b))    # Convert LAB image back to BGR    hist_eq_bgr = cv2.cvtColor(updated_lab_img, cv2.COLOR_LAB2BGR)    # Convert BGR back to RGB for matplotlib display    hist_eq_img = cv2.cvtColor(hist_eq_bgr, cv2.COLOR_BGR2RGB)    # CLAHE on L channel    clahe = cv2.createCLAHE(        clipLimit=3.0,        tileGridSize=(8, 8)    )    clahe_l = clahe.apply(l)    # Merge CLAHE-enhanced L channel with original A and B channels    updated_lab_img2 = cv2.merge((clahe_l, a, b))    # Convert LAB image back to BGR    clahe_bgr = cv2.cvtColor(updated_lab_img2, cv2.COLOR_LAB2BGR)    # Convert BGR back to RGB for matplotlib display    clahe_img = cv2.cvtColor(clahe_bgr, cv2.COLOR_BGR2RGB)fig = plt.figure(figsize=(12, 8))ax1 = fig.add_subplot(1, 3, 1)ax1.imshow(img, cmap="gray")ax1.set_title("Original Image")ax1.axis("off")ax2 = fig.add_subplot(1, 3, 2)ax2.imshow(hist_eq_img, cmap="gray")ax2.set_title("Histogram Equalization")ax2.axis("off")ax3 = fig.add_subplot(1, 3, 3)ax3.imshow(clahe_img, cmap="gray")ax3.set_title("CLAHE")ax3.axis("off")plt.tight_layout()plt.show()plt.figure(figsize=(12, 4))plt.subplot(1, 3, 1)plt.hist(img.flat, bins=100, range=(0, 255))plt.title("Original Histogram")plt.subplot(1, 3, 2)plt.hist(hist_eq_img.flat, bins=100, range=(0, 255))plt.title("Histogram Equalized")plt.subplot(1, 3, 3)plt.hist(clahe_img.flat, bins=100, range=(0, 255))plt.title("CLAHE Histogram")plt.tight_layout()plt.show()